mapper.select:
SELECT tp.id, tp.clinic_id AS clinicId, c.clinic_name AS clinicName, tp.plan_no AS planNo, tp.patient_id AS patientId, p.patient_name AS patientName, p.mobile AS patientMobile, tp.medical_record_id AS medicalRecordId, mr.record_no AS medicalRecordNo, tp.doctor_id AS doctorId, s.staff_name AS doctorName, tp.plan_name AS planName, tp.total_amount AS totalAmount, tp.plan_status AS planStatus, tp.start_date AS startDate, tp.end_date AS endDate, tp.remark, tp.created_at AS createdAt FROM treatment_plan tp LEFT JOIN clinic c ON c.id = tp.clinic_id LEFT JOIN patient p ON p.id = tp.patient_id LEFT JOIN medical_record mr ON mr.id = tp.medical_record_id LEFT JOIN staff s ON s.id = tp.doctor_id WHERE tp.org_id = #{orgId} AND tp.is_deleted = 0
AND tp.clinic_id = #{query.clinicId}
AND tp.patient_id = #{query.patientId}
AND tp.medical_record_id = #{query.medicalRecordId}
AND tp.doctor_id = #{query.doctorId}
AND tp.plan_status = #{query.planStatus}
AND ( tp.plan_no LIKE CONCAT('%', #{query.keyword}, '%') OR tp.plan_name LIKE CONCAT('%', #{query.keyword}, '%') OR p.patient_name LIKE CONCAT('%', #{query.keyword}, '%') OR p.mobile LIKE CONCAT('%', #{query.keyword}, '%') )
ORDER BY tp.created_at DESC, tp.id DESC
